/// EXTERNAL-PARMS
fn p_external_parms(state: &mut ProgramState) {
    println!("{}", "START OF EXECUTION OF PROGRAM CBACT04C");
    p_0000_tcatbalf_open(state);
    p_0100_xreffile_open(state);
    p_0200_discgrp_open(state);
    p_0300_acctfile_open(state);
    p_0400_tranfile_open(state);
    while !(&format!("{}", state.end_of_file) == &"Y".to_string()) {
        // SKIP: unresolved ref
    }
    p_9000_tcatbalf_close(state);
    p_9100_xreffile_close(state);
    p_9200_discgrp_close(state);
    p_9300_acctfile_close(state);
    p_9400_tranfile_close(state);
    println!("{}", "END OF EXECUTION OF PROGRAM CBACT04C");
    { let _ = state._fh_tcatbal_file.close();
        let _ = state._fh_xref_file.close();
        let _ = state._fh_discgrp_file.close();
        let _ = state._fh_account_file.close();
        let _ = state._fh_transact_file.close();
        return; }
}

/// 0000-TCATBALF-OPEN
fn p_0000_tcatbalf_open(state: &mut ProgramState) {
    state.appl_result = 8 as i32;
    tcatbal_file_open_input(state);
    if { let _s = format!("{}", state.tcatbalf_status); _s.trim().to_string() } == "00".to_string() {
        state.appl_result = 0 as i32;
    } else {
        state.appl_result = 12 as i32;
    }
    if state.appl_result == 0 {
    } else {
        println!("{}", "ERROR OPENING TRANSACTION CATEGORY BALANCE");
        {
            let mut _bytes = vec![b' '; 2];
            { let _src = state.tcatbalf_status.tcatbalf_stat1.as_bytes(); let _end = (0+1).min(_bytes.len()); let _cl = _src.len().min(_end-0); _bytes[0..0+_cl].copy_from_slice(&_src[.._cl]); }
            { let _src = state.tcatbalf_status.tcatbalf_stat2.as_bytes(); let _end = (1+1).min(_bytes.len()); let _cl = _src.len().min(_end-1); _bytes[1..1+_cl].copy_from_slice(&_src[.._cl]); }
            let _len = _bytes.len();
            if _len > 0 { let _end = _len.min(0+1); state.io_status.io_stat1 = FixedString::from(String::from_utf8_lossy(&_bytes[0.._end])); }
            if _len > 1 { let _end = _len.min(1+1); state.io_status.io_stat2 = FixedString::from(String::from_utf8_lossy(&_bytes[1.._end])); }
        }
        p_9910_display_io_status(state);
        p_9999_abend_program(state);
    }
}

