/// 1300-COMPUTE-INTEREST
fn p_1300_compute_interest(state: &mut ProgramState) {
    state.ws_misc_vars.ws_monthly_int = Decimal::from(i64::from((state.tran_cat_bal_record.tran_cat_bal * state.dis_group_record.dis_int_rate) / 1200));
    state.ws_misc_vars.ws_total_int += i64::from(state.ws_misc_vars.ws_monthly_int);
    p_1300_b_write_tx(state);
}

