/// READ TCATBAL-FILE
fn tcatbal_file_read(state: &mut ProgramState) -> Result<(), FileStatus> {
    match state._fh_tcatbal_file.read_line() {
        Ok(line) => {
            let _bytes = line.as_bytes();
            let _len = _bytes.len().min(50);
            if _len > 0 { let _end = _len.min(0+11); let _s = String::from_utf8_lossy(&_bytes[0.._end]).trim().to_string(); state.fd_trancat_acct_id = _s.parse().unwrap_or_default(); }
            if _len > 11 { let _end = _len.min(11+2); state.fd_trancat_type_cd = FixedString::from(String::from_utf8_lossy(&_bytes[11.._end])); }
            if _len > 13 { let _end = _len.min(13+4); let _s = String::from_utf8_lossy(&_bytes[13.._end]).trim().to_string(); state.fd_trancat_cd = _s.parse().unwrap_or_default(); }
            if _len > 17 { let _end = _len.min(17+33); state.fd_fd_tran_cat_data = FixedString::from(String::from_utf8_lossy(&_bytes[17.._end])); }
            state._fs_tcatbal_file = FileStatus::Success;
    { let _s = format!("{}", state._fs_tcatbal_file); let _b = _s.as_bytes(); unsafe { let p = &mut state.tcatbalf_status as *mut _ as *mut u8; for i in 0.._b.len().min(2) { *p.add(i) = _b[i]; } } }
        }
        Err(FileStatus::AtEnd) => {
            state._fs_tcatbal_file = FileStatus::AtEnd;
    { let _s = format!("{}", state._fs_tcatbal_file); let _b = _s.as_bytes(); unsafe { let p = &mut state.tcatbalf_status as *mut _ as *mut u8; for i in 0.._b.len().min(2) { *p.add(i) = _b[i]; } } }
        }
        Err(e) => {
            state._fs_tcatbal_file = e.clone();
    { let _s = format!("{}", state._fs_tcatbal_file); let _b = _s.as_bytes(); unsafe { let p = &mut state.tcatbalf_status as *mut _ as *mut u8; for i in 0.._b.len().min(2) { *p.add(i) = _b[i]; } } }
        }
    }
    Ok(())
}

/// WRITE to TCATBAL-FILE
fn tcatbal_file_write(state: &mut ProgramState) {
    let mut _buf = vec![b' '; 50];
    { let _s = format!("{:>width$}", state.fd_trancat_acct_id, width = 11); let _b = _s.as_bytes(); let _cl = _b.len().min(11); _buf[0..0+_cl].copy_from_slice(&_b[_b.len()-_cl..]); }
    { let _src = state.fd_trancat_type_cd.as_bytes(); let _end = (11+2).min(_buf.len()); let _cl = _src.len().min(_end-11); _buf[11..11+_cl].copy_from_slice(&_src[.._cl]); }
    { let _s = format!("{:>width$}", state.fd_trancat_cd, width = 4); let _b = _s.as_bytes(); let _cl = _b.len().min(4); _buf[13..13+_cl].copy_from_slice(&_b[_b.len()-_cl..]); }
    { let _src = state.fd_fd_tran_cat_data.as_bytes(); let _end = (17+33).min(_buf.len()); let _cl = _src.len().min(_end-17); _buf[17..17+_cl].copy_from_slice(&_src[.._cl]); }
    match state._fh_tcatbal_file.write_record(&_buf) {
        Ok(()) => state._fs_tcatbal_file = FileStatus::Success,
        Err(e) => state._fs_tcatbal_file = e,
    }
}

